// Configure the competitor technology name to watch for
const COMPETITOR_TECH = 'Salesforce'; // Change this to your competitor's tech

const item = $('🔄 Loop Over Companies').first().json;
const domain = item.domain;
const companyName = item.company_name || domain;
const aeEmail = item.ae_email;

const techData = $input.first().json.data || [];

// Check if any detected technology matches the competitor tech
const competitorMatches = techData.filter(tech => {
  const techName = (tech.technology_name || tech.name || '').toLowerCase();
  return techName.includes(COMPETITOR_TECH.toLowerCase());
});

const found = competitorMatches.length > 0;

return [{
  json: {
    domain,
    companyName,
    aeEmail,
    competitorTechFound: found,
    matchedTechnologies: competitorMatches.map(t => t.technology_name || t.name),
    totalTechDetections: techData.length,
    competitorTechName: COMPETITOR_TECH,
    checkDate: new Date().toISOString().split('T')[0]
  }
}];

// Extract and validate the AE email from the current item
const item = $input.first().json;

const aeEmail = (item.aeEmail || '').trim();

if (!aeEmail || !aeEmail.includes('@')) {
  // Skip if no valid AE email
  return [];
}

return [{
  json: {
    ...item,
    toEmail: aeEmail,
    emailSubject: `Competitor Alert: ${item.companyName} adopted ${item.competitorTechName}`,
    emailBody: [
      `Hi,`,
      ``,
      `A company in your portfolio has adopted competitor technology:`,
      ``,
      `**Company:** ${item.companyName}`,
      `**Domain:** ${item.domain}`,
      `**Competitor Tech Detected:** ${item.matchedTechnologies.join(', ')}`,
      `**Detection Date:** ${item.checkDate}`,
      ``,
      `This may indicate an opportunity to engage or a risk to address.`,
      ``,
      `- PredictLeads Monitoring`
    ].join('\n')
  }
}];
